#include <iostream>
#include <cmath>
#include <limits>

bool isPrime(int n) {
    n = std::abs(n);

    if (n <= 1) {
        return false;
    }
    for (int i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            return false;
        }
    }
    return true;
}

int main() {
    std::cout << std::boolalpha;
    std::cout << "Is 7 prime? " << isPrime(7) << std::endl;
    std::cout << "Is 4 prime? " << isPrime(4) << std::endl;
    std::cout << "Is 2 prime? " << isPrime(2) << std::endl;
    std::cout << "Is 1 prime? " << isPrime(1) << std::endl;
    std::cout << "Is 0 prime? " << isPrime(0) << std::endl;
    std::cout << "Is -5 prime? " << isPrime(-5) << std::endl;
    std::cout << "Is -4 prime? " << isPrime(-4) << std::endl;
    return 0;
}
